head.script:
/*
    NTIS/기본정보/거래처관리/거래처등록

    ▶  기타내용
        매입 체크박스 > 지급조건, 지불계좌 관련 컴포넌트 활성화 
        입력화면

    참고)
    asis: tbl_busi, tbl_clntPers 테이블 따로
    tobe: tbl_busi 테이블로 합침
*/


//화면상태 상수
scwin.STATE_NEW = "new";
scwin.STATE_UPDATE = "update";
scwin.STATE_COPY = "copy";
scwin.STATE_CONVERT = "convert";
scwin.STATE_VIEW = "retrieve";

//저장여부 상수 
scwin.NOT_SAVED = false;

//현재 화면상태
scwin.currentViewState = scwin.STATE_NEW;

//현재 저장상태
scwin.currentSaveState = scwin.NOT_SAVED;

//항상 Disable 상태
scwin.ALWAYS_DISABLED_OJECTS = null;

scwin.isCommonCodeLoaded = false;


//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = async function () {

};

scwin.onUdcCompleted = async function () {
    const codeOptions = [
        { grpCd: "ZZ602", compID: "lc_intrlnsClsCd" },
        { grpCd: "LO111", compID: "lc_sellClntClsCd" },
        { grpCd: "FI018", compID: "lc_busiClsCd" },
        { grpCd: "FM041", compID: "gr_payCond:payCycCd" },
        { grpCd: "ZZ522", compID: "gr_payCond:payDd" },
        { grpCd: "FM018", compID: "gr_payCond:payCntShtCd", opt: { "range": "3,99" } },
        { grpCd: "ZZ006", compID: "gr_payCond:payCrcCd, gr_collMoneyCond:collMoneyCrcCd" },
        { grpCd: "SD020", compID: "gr_collMoneyCond:stmtPrdClsCd" },
        { grpCd: "SD010", compID: "gr_collMoneyCond:collMoneyCntShtCd" },
        { grpCd: "FM019", compID: "gr_payAcnt:payClsCd" },
    ];
    $c.data.setCommonCode(codeOptions, function () {
        scwin.isCommonCodeLoaded = true;
    });

    while (!scwin.isCommonCodeLoaded) {
        await new Promise(resolve => setTimeout(resolve, 50));
    }

    $c.gus.cfInitHidVal([ed_mcomPicEmpNo, ed_upperClntNo, ed_bilgClntNo, ed_crn, ed_zip, ed_busiZip]);

    scwin.ALWAYS_DISABLED_OJECTS = [txt_clntNo, txt_addr1, txt_busiAddr1, txt_tmcMbrId
        , txt_mcomPicEmpNoNm, txt_deptNm, txt_persPstNm, txt_trfLnkYn];

    scwin.params = $c.data.getParameter();

    if (scwin.params == null || scwin.params["mode"] == null) {
        scwin.currentViewState = scwin.STATE_NEW;
        btn_close.setStyle("display", "none");

    } else {
        ds_search.set("clntNo", scwin.params["clntNo"]);
        ds_search.set("mbrId", scwin.params["mbrId"]);
        if (scwin.params["clntNo"] == null && scwin.params["mbrId"] == null) {
            scwin.currentViewState = scwin.STATE_NEW;
        } else {
            scwin.currentViewState = scwin.params["mode"];
        }
        btn_close.setStyle("display", "");
    }

    scwin.f_retrieve();
};


//-------------------------------------------------------------------------
// 거래처 조회
//-------------------------------------------------------------------------
scwin.f_retrieve = function () {
    if (scwin.currentViewState == scwin.STATE_COPY) {
        $c.sbm.execute(sbm_copy);
    } else {
        $c.sbm.execute(sbm_retrieve);
    }
};


//-------------------------------------------------------------------------
// 신규
//-------------------------------------------------------------------------
scwin.f_create = function () {
    ds_search.setEmptyValue();
    ds_search.set("clntNo", "");
    scwin.currentViewState = scwin.STATE_NEW;
    $c.sbm.execute(sbm_retrieve);
};


//-------------------------------------------------------------------------
// 화면상태 변경
//-------------------------------------------------------------------------
scwin.f_ChangeScreenState = function (state) {
    switch (state) {
        case scwin.STATE_NEW: scwin.f_setNewState(); break;
        case scwin.STATE_COPY: scwin.f_setCopyState(); break;
        case scwin.STATE_CONVERT: scwin.f_setConvertState(); break;
        case scwin.STATE_UPDATE: scwin.f_setUpdateState(); break;
        case scwin.STATE_VIEW: scwin.f_setViewState(); break;
        default: scwin.f_setNewState();
    }

    scwin.f_setMainBtnState(state);
    $c.gus.cfDisableObjects(scwin.ALWAYS_DISABLED_OJECTS);
};

scwin.f_setMainBtnState = function (state) {
    switch (state) {
        case scwin.STATE_NEW:
        case scwin.STATE_COPY:
        case scwin.STATE_CONVERT:

        case scwin.STATE_UPDATE:
            $c.gus.cfDisableObjects([btn_update]);
            $c.gus.cfEnableObjects([btn_save, btn_close]);
            break;

        case scwin.STATE_VIEW:
            $c.gus.cfDisableObjects([btn_save]);
            $c.gus.cfEnableObjects([btn_update, btn_close]);
            break;

        default:
            $c.gus.cfDisableObjects([btn_update]);
            $c.gus.cfEnableObjects([btn_save, btn_close]);
    }
};

scwin.f_setNewState = function () {
    scwin.f_ClearData([ds_clnt, ds_busi, ds_collMoneyCond, ds_payCond, ds_payAcnt]);
    ds_clnt.insertRow();
    ds_busi.insertRow();

    scwin.f_ClearCheck(["pchsSellCls", "bizDivCls", "transBizCls", "bizDomCls", "pchsClntcls"]);

    chk_sellClntYn.setValue("1");
    chk_pchsClntYn.setValue("0");
    chk_bizDivBulkYn.setValue("1");
    chk_bizDivCntrYn.setValue("1");
    chk_transBizYn.setValue("1");
    chk_bizDomTransYn.setValue("1");

    lc_intrlnsClsCd.setValue("01");	//타법인
    lc_sellClntClsCd.setValue("02");  //화주

    $c.gus.cfEnableObjects([tbl_clnt, tbl_busi]);

    scwin.f_TogglePchsClnt(chk_pchsClntYn.getValue());
    scwin.f_ToggleSellClnt(chk_sellClntYn.getValue());

    scwin.currentViewState = scwin.STATE_NEW;
};

scwin.f_setCopyState = function () {
    $c.gus.cfEnableObjects([tbl_clnt, tbl_busi]);

    scwin.f_TogglePchsClnt(chk_pchsClntYn.getValue());
    scwin.f_ToggleSellClnt(chk_sellClntYn.getValue());
    ds_clnt.setCellData(0, "clntNo", "");

    scwin.currentViewState = scwin.STATE_COPY;
};

scwin.f_setConvertState = function () {
    $c.gus.cfEnableObjects([tbl_clnt, tbl_busi]);

    scwin.f_TogglePchsClnt(chk_pchsClntYn.getValue());
    scwin.f_ToggleSellClnt(chk_sellClntYn.getValue());

    scwin.currentViewState = scwin.STATE_CONVERT;
};

scwin.f_setUpdateState = function () {
    $c.gus.cfEnableObjects([tbl_clnt, tbl_busi]);

    scwin.f_TogglePchsClnt(chk_pchsClntYn.getValue());
    scwin.f_ToggleSellClnt(chk_sellClntYn.getValue());

    $c.gus.cfDisableObjects([ed_crn, lc_busiClsCd]);

    scwin.currentViewState = scwin.STATE_UPDATE;
};

scwin.f_setViewState = function () {
    $c.gus.cfDisableObjects([tbl_clnt, tbl_busi]);

    scwin.f_TogglePchsClnt(false);
    scwin.f_ToggleSellClnt(false);

    scwin.currentViewState = scwin.STATE_VIEW;
};

//-------------------------------------------------------------------------
// 매출입구분 - 매출 체크박스 체크여부 확인
//-------------------------------------------------------------------------
scwin.f_ToggleSellClnt = function (sellClntYn) {
    if (sellClntYn == "1") {
        $c.gus.cfEnableObjects([lc_sellClntClsCd, tbl_collMoneyBtn]);
    } else if (sellClntYn == "0") {
        $c.gus.cfDisableObjects([lc_sellClntClsCd, tbl_collMoneyBtn]);
    }
};

//-------------------------------------------------------------------------
// 매출입구분 - 매입 체크박스 체크여부 확인
// > 지급조건, 지불계좌 그리드 세팅 버튼 disabled
//-------------------------------------------------------------------------
scwin.f_TogglePchsClnt = function (pchsClntYn) {
    if (pchsClntYn == "1") {
        $c.gus.cfEnableObjects([tbl_payCondBtn, tbl_payAcntNoBtn]);
    } else if (pchsClntYn == "0") {
        $c.gus.cfDisableObjects([tbl_payCondBtn, tbl_payAcntNoBtn]);
    }
    scwin.f_TogglePchsClntCls(pchsClntYn);
};

//-------------------------------------------------------------------------
// 매출입구분 - 매입 체크박스 체크여부 확인 > 매입거래처 체크박스 disabled
//-------------------------------------------------------------------------
scwin.f_TogglePchsClntCls = function (pchsClntYn) {
    var chkArr = [chk_pchsClntCls1, chk_pchsClntCls2, chk_pchsClntCls3, chk_pchsClntCls4];

    if (pchsClntYn == true) { // 체크
        $c.gus.cfEnableObjects(chkArr);
    } else if (pchsClntYn == false) {
        $c.gus.cfDisableObjects(chkArr);
    }
};

scwin.f_validate = async function () {
    if (!await $c.gus.cfValidate([tbl_clnt, tbl_busi], null, true)) {
        return false;
    }

    if (chk_sellClntYn.getValue() == "0" && chk_pchsClntYn.getValue() == "0") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["매출입구분"]);
        return false;
    }

    if (await scwin.f_validateSellClnt() == false) {
        return false;
    }
    if (await scwin.f_validatePchsClnt() == false) {
        return false;
    }

    return true;
};

scwin.f_validateSellClnt = async function () {
    if (chk_sellClntYn.getValue() == "0") {
        return true;
    }

    if ($c.gus.cfIsNull(lc_sellClntClsCd.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["매출거래처구분"]);
        return false;
    }

    if (chk_bizDivBulkYn.getValue() == "0" && chk_bizDivCntrYn.getValue() == "0") {	// 사업부문 항목 체크
        await $c.gus.cfAlertMsg("사업부문은 매출거래처 필수입력 사항입니다.");
        chk_bizDivCntrYn.setValue("1"); // bizDivCntrYn.checked= true;
        return false;
    }

    if (chk_bizDomTplYn.getValue() == "0" && chk_bizDomTransYn.getValue() == "0" &&
        chk_bizDomStvYn.getValue() == "0" && chk_bizDomStrYn.getValue() == "0") {	// 사업영역 항목 체크
        await $c.gus.cfAlertMsg("사업영역은 매출거래처 필수입력 사항입니다.");
        return false;
    }

    if (ds_collMoneyCond.getTotalRow() == 0 && !(lc_intrlnsClsCd.getValue() != "02" && lc_sellClntClsCd.getValue() == "02")) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_053, ["수금조건"]);
        return false;
    }

    if (!await $c.gus.cfValidate([gr_collMoneyCond], null, true)) {
        return false;
    }

    if (scwin.f_ExistSameRowYn(ds_collMoneyCond
        , ["adptDt", "collMoneyAcctDeptCd", "stmtPrdClsCd", "stmtPrdDd"
            , "collMoneyCntShtCd", "draftDdCnt", "collMoneyCrcCd"])) {
        await $c.gus.cfAlertMsg("동일한 수금조건이 존재합니다.");
        return false;
    }

    return true;
};

scwin.f_validatePchsClnt = async function () {
    if (chk_pchsClntYn.getValue() == "0") {
        return true;
    }

    if (chk_transBizYn.getValue() == "0" && chk_transIntcdBizYn.getValue() == "0") { // 운송사업부분
        await $c.gus.cfAlertMsg("운송사업구분은 매입거래처 필수입력 사항입니다.");
        return false;
    }

    if (await scwin.f_validatePayCond() == false) {
        return false;
    }
    if (await scwin.f_validatePayAcnt() == false) {
        return false;
    }

    return true;
};

scwin.f_validatePayCond = async function () {
    if (ds_payCond.getTotalRow() == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_053, ["지불조건"]);
        return false;
    }

    let validArray = [
        { id: "adptDt", name: "적용일자", mandatory: true },
        { id: "payCycCd", name: "지급주기", mandatory: true },
        { id: "payCntShtCd", name: "지급수단", mandatory: true },
    ];
    let ret = await $c.gus.cfValidateGrid(gr_payCond, null, null, validArray, "지급조건");
    if (!ret) {
        return false;
    }

    if (scwin.f_ExistSameRowYn(ds_payCond
        , ["adptDt", "payAcctDeptCd", "mbssysVehclYn", "mchtClntNo", "payCycCd"
            , "payDd", "payCntShtCd", "draftDdCntCd", "payCrcCd", "cashRt", "draftRt"])) {
        await $c.gus.cfAlertMsg("동일한 지불조건이 존재합니다.");
        return false;
    }

    for (var i = 0; i < ds_payCond.getTotalRow(); i++) {
        if (ds_payCond.getCellData(i, "payCntShtCd") == "50" && $c.gus.cfIsNull(ds_payCond.getCellData(i, "draftDdCntCd"))) {
            await $c.gus.cfAlertMsg("지급조건의 지급수단이 실물어음,전자결제일경우 어음일수를 입력하셔야 합니다.");
            gr_payCond.setFocusedCell(i, "draftDdCntCd");
            return false;
        }

        if (ds_payCond.getCellData(i, "payCntShtCd") == "25" && $c.gus.cfIsNull(ds_payCond.getCellData(i, "draftDdCntCd")) && ds_payCond.getCellData(i, "cashRt") != "100") {
            await $c.gus.cfAlertMsg("지급조건의 지급수단이 실물어음,전자결제일경우 어음일수를 입력하셔야 합니다.");
            gr_payCond.setFocusedCell(i, "draftDdCntCd");
            return false;
        }

        if (ds_payCond.getCellData(i, "mbssysVehclYn") == "1" && $c.gus.cfIsNull(ds_payCond.getCellData(i, "mchtClntNm"))) {
            await $c.gus.cfAlertMsg("지급조건이 회원제차량인 경우 화주거래처 입력은 필수사항입니다.");
            gr_payCond.setFocusedCell(i, "mchtClntNm");
            return false;
        }
    }

    return true;
};

scwin.f_validatePayAcnt = async function () {
    if (ds_payAcnt.getTotalRow() == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_053, ["지급계좌"]);
        return false;
    }

    if (await $c.gus.cfValidate([gr_payAcnt], null, true) == false) {
        return false;
    }

    if (scwin.f_ExistSameRowYn(ds_payAcnt
        , ["adptDt", "payClsCd", "bankCd", "bankAcntNo", "dpstrNm", "elecStmtBankCd", "transfCmisDeductYn"])) {
        await $c.gus.cfAlertMsg("동일한 지불계좌가 존재합니다.");
        return false;
    }

    return true;
};

scwin.f_IsPchsClntClsChnaged = function () {
    /*
    var chkArr = [
        { id: "chk_pchsClntCls1", cd: "01" }, // 용차
        { id: "chk_pchsClntCls2", cd: "02" }, // 위수탁
        { id: "chk_pchsClntCls3", cd: "03" }, // 자차
        { id: "chk_pchsClntCls4", cd: "04" }  // 지입
    ]

    for (var i = 0; i < chkArr.length; i++) {

    }

    for(var i=0; i < objArray.length; i++) {
        var obj = objArray[i];
        var row = ds_pchsClntCls.NameValueRow("pchsClntClsCd", obj.value);

        if((obj.checked && ds_pchsClntCls.NameValue(row,"chk") != 1) || (!obj.checked && ds_pchsClntCls.NameValue(row,"chk") == 1)) {
            return true;
        }
    }
    return false;
    */
};


//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_save = async function () {
    if (scwin.f_IsUpdated([ds_clnt, ds_busi, ds_collMoneyCond, ds_payCond, ds_payAcnt]) == false
        && scwin.f_IsPchsClntClsChnaged() == false) {
        await $c.gus.cfAlertMsg("변경된 사항이 없습니다.");
        return false;
    }

    // 결제구분은 Bill 수령후를 선택할 수 없게함
    if (ds_collMoneyCond.getCellData(0, 'stmtPrdClsCd') == "02") {
        await $c.win.alert("결제 구분은 Bill 수령후를 선택하실 수 없습니다.");
        return 0;
    }

    if (txt_clntTelNo.getValue().length == 0 && txt_clntMpNo.getValue().length == 0) {
        await $c.gus.cfAlertMsg("유선전화와 휴대전화 둘 중 하나는 필수입력입니다 .");
        return false;
    }

    if (await scwin.f_validate() == false) {
        return;
    }

    if (!await $c.win.confirm(MSG_CM_CRM_001)) {
        return;  //저장하시겠습니까?
    }

    scwin.f_makePchsClntClsDataset();

    ds_clnt.setRowPosition(0);
    ds_busi.setRowPosition(0);
    ds_busi.setCellData(0, "crn", ed_crn.getValue());
    ds_busi.setCellData(0, "busiClsCd", lc_busiClsCd.getValue());

    $c.sbm.setAction(sbm_save, scwin.f_getSaveAction());
    $c.sbm.execute(sbm_save);
};

scwin.f_getSaveAction = function () {
    if (scwin.currentViewState == scwin.STATE_VIEW) {
        return "";
    }

    if (scwin.currentViewState == scwin.STATE_UPDATE) {
        return "/ncall.tn.cs.clntmgnt.UpdateClntCMD.do";
    } else {
        return "/ncall.tn.cs.clntmgnt.RegistClntCMD.do";
    }
};

// 체크된 매입거래처구분을 저장할 데이터셋으로 복사
scwin.f_makePchsClntClsDataset = function () {
    /*
    ds_pchsClntCls.ClearData();	
    for( var i=0; i < document.getElementsByName("pchsClntCls").length; i ++){
        var objChk = document.getElementsByName("pchsClntCls")[i];
        if(objChk.checked==true){
            ds_pchsClntCls.AddRow();
            ds_pchsClntCls.NameValue(ds_pchsClntCls.RowPosition, "pchsClntClsCd") = objChk.value;
            ds_pchsClntCls.NameValue(ds_pchsClntCls.RowPosition, "chk") = 1;
        }
    }
    */
};



//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.f_update = function () {
    scwin.f_ChangeScreenState(scwin.STATE_UPDATE);
};


//-------------------------------------------------------------------------
// 사업장 주소 팝업
//-------------------------------------------------------------------------
scwin.f_openZipPopUp = async function (pClose) {
    // 사업장주소 udc codeId, nameId
    var codeObj = ed_zip;
    var nameObj = txt_addr1;

    if (pClose == 'T' && !$c.gus.cfCanOpenPopup(codeObj, nameObj)) {
        return;
    }

    var rtnList = new Array();
    var opts = {
        id: "smpPop"
        , popupName: ""
        , modal: true
        , type: "browserPopup"  //화면 오픈 타입 ("pageFramePopup", "browserPopup")
        , title: "Win pop"  //Layer pop
        , width: 750
        , height: 600
    };

    var popupResult = await $c.win.openPopup("/ui/cm/zz/zipcodePopupNcall.xml", opts);

    ed_zip.setValue(popupResult.zip); //출발지 우편번호
    txt_addr1.setValue(popupResult.addr1); //출발지 우편번호

    if (popupResult != null && popupResult[0] != "N/A" && busiZip_check) {
        // 청구지주소 udc
        ed_busiZip.setValue($c.gus.cfGetValue(codeObj));
        txt_busiAddr1.setValue($c.gus.cfGetValue(nameObj));
    }
};

//-------------------------------------------------------------------------
// 주소 수령지 팝업
//-------------------------------------------------------------------------
scwin.f_openBusiZipPopUp = async function (pClose) {
    var codeObj = ed_busiZip;
    var nameObj = txt_busiAddr1;

    if (pClose != 'F' && !$c.gus.cfCanOpenPopup(codeObj, nameObj)) {
        return;
    }

    var rtnList = new Array();
    var opts = {
        id: "smpPop"
        , popupName: ""
        , modal: true
        , type: "browserPopup"  //화면 오픈 타입 ("pageFramePopup", "browserPopup")
        , title: "Win pop"  //Layer pop
        , width: 750
        , height: 400
    };

    var popupResult = await $c.win.openPopup("/ui/cm/zz/zipcodePopupNcall.xml", opts);

    if (popupResult != null) {
        if (popupResult[0] == "N/A") {
            return;
        }

        ed_busiZip.setValue(popupResult.zip); //출발지 우편번호
        txt_busiAddr1.setValue(popupResult.addr1); //출발지 우편번호

        if (popupResult != null && popupResult[0] != "N/A") {
            if (ed_zip.getValue() == ed_busiZip.getValue()) {
                busiZip_check.setValue("1");
            } else {
                busiZip_check.setValue("0");
            }
        }

    } else {
        ed_busiZip.setValue(""); //출발지 우편번호
        txt_busiAddr1.setValue(""); //출발지 우편번호
    }
};

//-------------------------------------------------------------------------
//우편물수령지 checkbox
//-------------------------------------------------------------------------
scwin.f_zipCheckBox = function () {
    if (busiZip_check.getValue() == "1") {
