// 수금조건 행 추가
scwin.f_ClntCollMoneyCondAddRow = function () {
    // 제일 위에 행추가됨
    ds_collMoneyCond.insertRow(0);
    ds_collMoneyCond.setRowPosition(0);
    ds_collMoneyCond.setCellData(0, "adptDt", $c.date.getServerDateTime("yyyyMMdd"));
    ds_collMoneyCond.setCellData(0, "seq", scwin.f_TakeNum(ds_collMoneyCond, "seq"));
    ds_collMoneyCond.setCellData(0, "collMoneyCrcCd", "KRW");
}

// 수금조건 행 삭제
scwin.f_ClntCollMoneyCondDelMarked = async function () {
    var rowIdx = ds_collMoneyCond.getRowPosition();

    if (ds_collMoneyCond.getCellData(rowIdx, "confirmYn") == "1") {
        await $c.gus.cfAlertMsg("확인된 건은 삭제 할 수 없습니다.");

    } else {
        // ds_collMoneyCond.DeleteMarked();
        if (ds_collMoneyCond.getRowStatus(rowIdx) == "C") {
            ds_collMoneyCond.removeRow(rowIdx);
        } else {
