scwin.f_ClearCheck = function (className) {
    if ($c.gus.cfIsNull(className)) {
        return;
    }

    if (scwin.f_IsArray(className)) {
        for (var i = 0; i < className.length; i++) {
            scwin.f_ClearCheck(className[i]);
        }
    } else {
        var objArray = scwin.f_getElementsByClass(className);
        for (var i = 0; i < objArray.length; i++) {
            if (objArray[i].type == "checkbox" || objArray[i].type == "CHECKBOX") {
                objArray[i].checked = false;
            }
        }
    }
};



scwin.f_getElementsByClass = function (className) {
    if ($c.gus.cfIsNull(className)) {
        return [];
    }

    var objArray = [];
    for (var i = 0; i < document.all.length; i++) {
        var obj = document.all[i];
        if (!$c.gus.cfIsNull(obj.className) && (obj.className.indexOf(className) != -1)) {
            objArray[objArray.length] = obj;
        }
    }
    return objArray;
};



scwin.f_IsArray = function (inObj) {
    return (inObj instanceof Array);
};



scwin.f_ExistSameRowYn = function (dataSet, colArray) {
    if (dataSet == null || colArray == null) {
        return false;
    }
    if (dataSet.getTotalRow() <= 1) {
        return false;
    }

    for (var i = 0; i < dataSet.getTotalRow(); i++) {
        for (var j = i + 1; j < dataSet.getTotalRow(); j++) {
            if (i == j) {
                continue;
            }
            if (scwin.f_getRowDataStr(dataSet, i, colArray) == scwin.f_getRowDataStr(dataSet, j, colArray)) {
                return true;
            }
        }
    }
    return false;
};


scwin.f_getRowDataStr = function (dataSet, row, colArray) {
    if (dataSet == null || colArray == null || row == null) {
        return "";
    }

    if (!scwin.f_IsArray(colArray)) {
        return "";
    }

    if (row < 0) {
        return "";
    }

    var retArray = [];
    for (var i = 0; i < colArray.length; i++) {
        retArray[retArray.length] = dataSet.getCellData(row, colArray[i]);
    }
    return retArray.toString();
};


// 데이터셋의 자료 변경 여부를 반환 :
scwin.f_IsUpdated = function (dataSet) {
    if (dataSet == null) {
        return false;
    }

    if (scwin.f_IsArray(dataSet)) {
        for (var i = 0; i < dataSet.length; i++) {
            if (scwin.f_IsUpdated(dataSet[i])) {
                return true;
            }
        }
    } else {
        if (dataSet.getModifiedIndex().length != 0) {
            return true;
        }
    }
    return false;
};



scwin.f_ClearData = function (dataSet) {
    if (dataSet == null) {
        return false;
    }

    if (scwin.f_IsArray(dataSet)) {
        for (var i = 0; i < dataSet.length; i++) {
            scwin.f_ClearData(dataSet[i]);
        }
    } else {
        dataSet.removeAll();
    }
};



// 그리드 컬럼 선택 시 inputType 변경?
scwin.f_ChangeGridPopupBtn = function (grid, colid) {
