//-------------------------------------------------------------------------
scwin.sbm_member_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;	// OnFail

    var rowCnt = ds_member.getTotalRow();
    if (rowCnt == 0) {
        await $c.gus.cfAlertMsg("회원정보가 없습니다.");
        scwin.f_close();
        return;
    }

    ds_clnt.removeAll();
    ds_busi.removeAll();

    ds_clnt.insertRow();
    ds_busi.insertRow();

    rd_copCoEstmtYn.setValue("0");													                        //협력업체평가여부 - 아니오
    chk_sellClntYn.setValue(["01", "02", "03"].includes(ds_member.getCellData(0, "mbrClsCd")) ? "1" : "0");   //매출거래처여부 - 화주,선사, 포워드
    chk_pchsClntYn.setValue(["04", "05"].includes(ds_member.getCellData(0, "mbrClsCd")) ? "1" : "0");        //매입거래처여부 - 화주,선사, 포워드
    chk_bizDivBulkYn.setValue(ds_member.getCellData(0, "bulkYn") == "1" ? "1" : "0");						// 벌크여부
    chk_bizDivCntrYn.setValue(ds_member.getCellData(0, "cntrYn") == "1" ? "1" : "0");						// 컨테이너여부
    lc_intrlnsClsCd.setValue("01");														//계열구분 - 타법인
    chk_bizDomTransYn.setValue(chk_sellClntYn.getValue());    									// 사업영역 - 운송사업
    chk_transBizYn.setValue(chk_pchsClntYn.getValue());    									// 운송사업부분 - 운송사업

    // 회원구분 코드 값에 따라 매출 거래처구분 변경, 운송사업부 변경, 거래처구분 변경
    switch (ds_member.getCellData(0, "mbrClsCd")) {
        case "01":		//화주
        case "03":     //포워드
            lc_sellClntClsCd.setValue("02");		// 화주
            break
        case "02":     //선사
            lc_sellClntClsCd.setValue("01");		// 선사
    }

    $c.gus.f_CopyDataRow(ds_member, ds_clnt, 0, ds_clnt.getRowPosition()
        , ["busiNm", "tmcMbrId", "mbrNm", "telNo", "mpNo", "faxNo", "email"]
        , ["clntNm", "mbrId", "clntPersNm", "clntTelNo", "clntMpNo", "clntFaxNo", "clntEmail"]);

    $c.gus.f_CopyDataRow(ds_member, ds_busi, 0, ds_busi.getRowPosition()
        , ["busiClsCd", "crn", "repstNm", "biztypeNm", "bizcondNm", "busiZip", "busiAddr1", "busiAddr2", "mailZip", "mailAddr1", "mailAddr2"]
        , ["busiClsCd", "crn", "repstNm", "biztypeNm", "bizcondNm", "zip", "addr1", "addr2", "busiZip", "busiAddr1", "busiAddr2"]);

    scwin.f_ChangeCrnInputFormat(lc_busiClsCd.getValue());
    scwin.f_ChangeScreenState(scwin.STATE_CONVERT);
};


//-------------------------------------------------------------------------
// 수금수단 Combo 선택
// ASIS : for=gr_collMoneyCond event=OnCloseUp(row,colid)
//-------------------------------------------------------------------------
scwin.gr_collMoneyCond_oneditend = function (rowIndex, columnIndex, value) {
    var colid = gr_collMoneyCond.getColumnID(columnIndex);

    if (colid == "collMoneyCntShtCd") {
        if (value == "20" || value == "") {	// 수금수단이 어음인 경우, 행추가 시(value="")
            ds_collMoneyCond.setCellData(rowIndex, "draftDdCnt", 0);
            gr_collMoneyCond.setColumnReadOnly("draftDdCnt", false);
        } else {
            gr_collMoneyCond.setColumnReadOnly("draftDdCnt", true);
            ds_collMoneyCond.setCellData(rowIndex, "draftDdCnt", 0);
        }

    } else if (colid == "stmtPrdClsCd") {
        gr_collMoneyCond.setColumnReadOnly("stmtPrdDd", false);
        ds_collMoneyCond.setCellData(rowIndex, "stmtPrdDd", "30");
    }
};


//-------------------------------------------------------------------------
// ASIS : 
// for=gr_payCond event=OnCloseUp(row,colid)
//-------------------------------------------------------------------------
scwin.gr_payCond_oneditend = function (rowIndex, columnIndex, value) {
    var colid = gr_payCond.getColumnID(columnIndex);

    // 지급주기, 주기일콤보를 여는 경우
    if (colid == "payCycCd") {
        if (value == "0" || value == "") {	// 수시인 경우, 행추가 직후(value=="")
            ds_payCond.setCellData(rowIndex, "payDd", "");
            gr_payCond.setColumnReadOnly("payDd", true);
        } else {	// 익월, 익익월인 경우
            gr_payCond.setColumnReadOnly("payDd", false);
            ds_payCond.setCellData(rowIndex, "payDd", "10");
        }

    } else if (colid == "payCntShtCd") {
        if (value == "25" || value == "50" || value == "") {   // 전자결재(25)이나 실물어음(50)인 경우, 행추가 직후(value=="")
            gr_payCond.setColumnReadOnly("draftDdCntCd", false);
        } else {
            gr_payCond.setColumnReadOnly("draftDdCntCd", true);
            ds_payCond.setCellData(rowIndex, "draftDdCntCd", "");
        }
    }
};


//-------------------------------------------------------------------------
// 현금과 어음비율 값 입력 
// ASIS : for=ds_payCond  event=onColumnChanged(row,colid)
//-------------------------------------------------------------------------
scwin.ds_payCond_oncelldatachange = async function (info) {
    var colid = info.colID;
    var row = info.rowIndex;

    if (colid == "cashRt") { //현금
        if (scwin.f_IsBetween(ds_payCond.getCellData(row, "cashRt"), 0, 100)) {
            ds_payCond.setCellData(row, "draftRt", (100 - ds_payCond.getCellData(row, "cashRt")));
        } else {
            await $c.gus.cfAlertMsg("현금비율은 입력값이 100보다 클 수 없습니다.");
            ds_payCond.setCellData(row, "cashRt", (100 - ds_payCond.getCellData(row, "draftRt")));
        }

    } else if (colid == "draftRt") { //어음
        if (scwin.f_IsBetween(ds_payCond.getCellData(row, "draftRt"), 0, 100)) {
            ds_payCond.setCellData(row, "cashRt", (100 - ds_payCond.getCellData(row, "draftRt")));
        } else {
            await $c.gus.cfAlertMsg("어음비율은 입력값이 100보다 클 수 없습니다.");
            ds_payCond.setCellData(row, "draftRt", (100 - ds_payCond.getCellData(row, "cashRt")));
        }
    }
};


